#include<bits/stdc++.h>
using namespace std;
int n,m;
vector<pair<int,int>> mp[200010];
int scc[200010],dfn[200010],scccnt,low[200010],dfncnt,siz[200010];
bool instk[200010];
stack<int> s;
void tarjan(int x)
{
    dfn[x]=low[x]=++dfncnt;
    instk[x]=1;
    s.push(x);
    for(auto i:mp[x])
    {
        int v=i.first;
        if(!dfn[v])
        {
            tarjan(v);
            low[x]=min(low[x],low[v]);
        }
        else if(instk[v])
        {
            low[x]=min(low[x],dfn[v]);
        }
    }
    if(dfn[x]==low[x])
    {
        int top;
        scccnt++;
        do
        {
            top=s.top();
            s.pop();
            siz[scccnt]++;
            scc[top]=scccnt;
            instk[top]=0;
        }while(top!=x);
    }
}
int in[200010],dp[200010];
vector<pair<int,int>> mp1[200010];
int main()
{
    scanf("%d%d",&n,&m);
    for(int i=1;i<=m;i++)
    {
        int t,x,y;
        scanf("%d%d%d",&t,&x,&y);
        if(t==1)
        {
            mp[x].push_back(make_pair(y,0));
            mp[y].push_back(make_pair(x,0));
        }
        else if(t==2)
        {
            mp[x].push_back(make_pair(y,1));
        }
        else if(t==3)
        {
            mp[y].push_back(make_pair(x,0));
        }
        else if(t==4)
        {
            mp[y].push_back(make_pair(x,1));
        }
        else
        {
            mp[x].push_back(make_pair(y,0));
        }
    }
    for(int i=1;i<=n;i++)
    {
        if(!dfn[i])
        {
            tarjan(i);
        }
    }
    for(int i=1;i<=n;i++)
    {
        for(auto v:mp[i])
        {
            int j=v.first;
            if(scc[i]!=scc[j])
            {
                in[scc[j]]++;
                mp1[scc[i]].push_back(make_pair(scc[j],v.second));
            }
            else if(v.second)
            {
                printf("-1");
                return 0;
            }
        }
    }
    queue<int> q;
    for(int i=1;i<=scccnt;i++)
    {
        if(in[i]==0)
        {
            dp[i]=1;
            q.push(i);
        }
    }
    long long ans=0;
    while(!q.empty())
    {
        int t=q.front();
        q.pop();
        ans+=1ll*dp[t]*siz[t];
        for(auto i:mp1[t])
        {
            int v=i.first,val=i.second;
            in[v]--;
            dp[v]=max(dp[v],dp[t]+val);
            if(in[v]==0)
            {
                q.push(v);
            }
        }
    }
    printf("%lld",ans);
    return 0;
}
